"use client";

import { useState } from "react";

export default function PendingActionCard() {

  const [status, setStatus] = useState<
    "idle" | "sending" | "approved"
  >("idle");

  const handleApprove = () => {

    setStatus("sending");

    // simulate network request
    setTimeout(() => {
      setStatus("approved");
    }, 2000);

  };

  return (

    <div
      className={`max-w-md p-6 rounded-2xl shadow-lg border transition-all
      ${
        status === "approved"
          ? "bg-green-50 border-green-400"
          : "bg-white"
      }`}
    >

      <h2 className="text-lg font-semibold mb-4">
        Pending Email Approval
      </h2>

      <div className="text-sm space-y-2 mb-4">

        <p>
          <strong>To:</strong> students@college.edu
        </p>

        <p>
          <strong>Subject:</strong> Rescheduled Lab Exam
        </p>

        <p>
          <strong>Body:</strong>
          Please note the lab exam is moved to Friday at 10 AM.
        </p>

      </div>

      <button

        onClick={handleApprove}

        disabled={status !== "idle"}

        className={`w-full py-2 rounded-xl font-medium transition
        ${
          status === "approved"
            ? "bg-green-500 text-white"
            : "bg-black text-white hover:bg-gray-800"
        }
        ${status === "sending" && "opacity-70 cursor-not-allowed"}
      `}

      >

        {status === "idle" && "Approve & Send"}

        {status === "sending" && "Sending..."}

        {status === "approved" && "Approved ✅"}

      </button>

    </div>

  );
}